def solve(list1_str, list2_str):
    list1 = list1_str.split(); list2 = list2_str.split()
    idx1 = {v: i for i, v in enumerate(list1)}
    best = float('inf'); res = []
    for j, v in enumerate(list2):
        if v in idx1:
            total = idx1[v] + j
            if total < best: best = total; res = [v]
            elif total == best: res.append(v)
    return ' '.join(res)

